import{_ as e,o as l,c as a,ag as d}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Heroku 别名 | Dotfiles (ZH)","titleTemplate":":title","description":"使用 200+ shell 别名加速 Heroku 工作流，涵盖应用、数据库、流水线和部署。","frontmatter":{"title":"Heroku 别名 | Dotfiles","description":"使用 200+ shell 别名加速 Heroku 工作流，涵盖应用、数据库、流水线和部署。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Heroku 别名 preview","canonical":"/zh/aliases/heroku/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Heroku 别名","pageType":"docs","schemaType":"WebPage","metaTitle":"Heroku 别名 - Dotfiles (CN)","permalink":"/zh/aliases/heroku/","sidebar":true,"meta":[{"name":"keywords","content":"heroku 别名, heroku cli 快捷方式, heroku shell 命令, dotfiles, paas 部署, heroku postgres"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Heroku 别名 - Dotfiles"},{"name":"twitter:description","content":"使用 200+ shell 别名加速 Heroku 工作流，涵盖应用、数据库、流水线和部署。"},{"name":"og:title","content":"Heroku 别名 - Dotfiles"},{"name":"og:description","content":"使用 200+ shell 别名加速 Heroku 工作流，涵盖应用、数据库、流水线和部署。"},{"name":"og:image:alt","content":"Dotfiles - 为你的 Shell 生活精心设计"},{"name":"og:locale","content":"zh_CN"}]},"headers":[],"relativePath":"zh/aliases/heroku/index.md","filePath":"zh/aliases/heroku/index.md","lastUpdated":1773010926000}'),r={name:"zh/aliases/heroku/index.md"};function o(i,t,n,s,h,c){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="heroku-别名" tabindex="-1">Heroku 别名 <a class="header-anchor" href="#heroku-别名" aria-label="Permalink to &quot;Heroku 别名&quot;">​</a></h1><p>Heroku CLI 的 Shell 快捷方式，定义在 <code>heroku.aliases.sh</code> 中，由 chezmoi 自动加载。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>此集合为 <a href="https://devcenter.heroku.com/articles/heroku-cli" target="_blank" rel="noreferrer">Heroku CLI</a> 提供超过 200 个别名，涵盖应用管理、插件、数据库、流水线、容器等。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><h3 id="通用命令" tabindex="-1">通用命令 <a class="header-anchor" href="#通用命令" aria-label="Permalink to &quot;通用命令&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>hkk</code></td><td style="text-align:left;">Heroku CLI 命令快捷方式</td></tr><tr><td style="text-align:left;"><code>hka</code></td><td style="text-align:left;">添加新用户到应用</td></tr><tr><td style="text-align:left;"><code>hkh</code></td><td style="text-align:left;">显示 Heroku 帮助</td></tr><tr><td style="text-align:left;"><code>hkl</code></td><td style="text-align:left;">列出所有命令</td></tr><tr><td style="text-align:left;"><code>hklg</code></td><td style="text-align:left;">显示最近日志输出</td></tr><tr><td style="text-align:left;"><code>hkn</code></td><td style="text-align:left;">显示通知</td></tr><tr><td style="text-align:left;"><code>hks</code></td><td style="text-align:left;">显示 Heroku 平台当前状态</td></tr><tr><td style="text-align:left;"><code>hku</code></td><td style="text-align:left;">更新 Heroku CLI</td></tr></tbody></table><h3 id="应用" tabindex="-1">应用 <a class="header-anchor" href="#应用" aria-label="Permalink to &quot;应用&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>hkapc</code></td><td style="text-align:left;">创建新应用</td></tr><tr><td style="text-align:left;"><code>hkapi</code></td><td style="text-align:left;">显示应用详情</td></tr><tr><td style="text-align:left;"><code>hkapk</code></td><td style="text-align:left;">永久删除应用</td></tr><tr><td style="text-align:left;"><code>hkapl</code></td><td style="text-align:left;">列出应用</td></tr><tr><td style="text-align:left;"><code>hkapo</code></td><td style="text-align:left;">在浏览器中打开应用</td></tr><tr><td style="text-align:left;"><code>hkapr</code></td><td style="text-align:left;">重命名应用</td></tr><tr><td style="text-align:left;"><code>hkapt</code></td><td style="text-align:left;">转移应用到其他用户或团队</td></tr></tbody></table><h3 id="配置变量" tabindex="-1">配置变量 <a class="header-anchor" href="#配置变量" aria-label="Permalink to &quot;配置变量&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>hkcfv</code></td><td style="text-align:left;">显示应用的配置变量</td></tr><tr><td style="text-align:left;"><code>hkcfs</code></td><td style="text-align:left;">设置一个或多个配置变量</td></tr><tr><td style="text-align:left;"><code>hkcfu</code></td><td style="text-align:left;">取消设置一个或多个配置变量</td></tr><tr><td style="text-align:left;"><code>hkcfg</code></td><td style="text-align:left;">显示单个配置值</td></tr></tbody></table><h3 id="postgresql" tabindex="-1">PostgreSQL <a class="header-anchor" href="#postgresql" aria-label="Permalink to &quot;PostgreSQL&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>hkpg</code></td><td style="text-align:left;">显示数据库信息</td></tr><tr><td style="text-align:left;"><code>hkpgbk</code></td><td style="text-align:left;">列出数据库备份</td></tr><tr><td style="text-align:left;"><code>hkpgbkc</code></td><td style="text-align:left;">捕获新备份</td></tr><tr><td style="text-align:left;"><code>hkpgbkr</code></td><td style="text-align:left;">恢复备份</td></tr><tr><td style="text-align:left;"><code>hkpgpsql</code></td><td style="text-align:left;">打开数据库 psql shell</td></tr></tbody></table><h3 id="流水线" tabindex="-1">流水线 <a class="header-anchor" href="#流水线" aria-label="Permalink to &quot;流水线&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>hkpipe</code></td><td style="text-align:left;">列出可访问的流水线</td></tr><tr><td style="text-align:left;"><code>hkpipec</code></td><td style="text-align:left;">创建新流水线</td></tr><tr><td style="text-align:left;"><code>hkpipei</code></td><td style="text-align:left;">显示流水线中的应用列表</td></tr><tr><td style="text-align:left;"><code>hkpipep</code></td><td style="text-align:left;">提升应用的最新版本到下游应用</td></tr></tbody></table><h3 id="容器" tabindex="-1">容器 <a class="header-anchor" href="#容器" aria-label="Permalink to &quot;容器&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>hkct</code></td><td style="text-align:left;">使用容器构建和部署 Heroku 应用</td></tr><tr><td style="text-align:left;"><code>hkctin</code></td><td style="text-align:left;">登录 Heroku Container Registry</td></tr><tr><td style="text-align:left;"><code>hkctpush</code></td><td style="text-align:left;">构建并推送 Docker 镜像</td></tr><tr><td style="text-align:left;"><code>hkctrelease</code></td><td style="text-align:left;">发布之前推送的 Docker 镜像</td></tr></tbody></table>',17)])])}const x=e(r,[["render",o]]);export{g as __pageData,x as default};
